def _early_thread_count():
    """Decide the torch thread count from argv BEFORE any heavy import initializes the OMP
    pool. On hosts with a duplicated libomp, RESIZING the pool after init segfaults (OMP
    #179), so the count must be fixed once, up front. stage1 (huge feature matmuls) -> 1;
    stage2/training -> --threads (default 10). The 'all' orchestrator does no torch compute."""
    av = sys.argv
    phase = av[av.index("--phase") + 1] if "--phase" in av else "all"
    if phase == "stage1":
        return 1
    if "--threads" in av:
        try:
            return int(av[av.index("--threads") + 1])
        except Exception:  # noqa: BLE001
            return 10
    return 10


torch.set_num_threads(_early_thread_count())

